solutions.cpp:
class Solution {
public:
    string solve(vector<string>& strings) {
        StringBuilder sb;
        for (const string& s : strings) {
            if (!s.empty()) sb += s;
        }
        return sb.str();
    }
};

solutions.java:
public class Solution {
    public String solve(String[] strings) {
        StringBuilder sb;
        for (String s : strings) {
            if (!s.isEmpty()) sb.append(s);
        }
        return sb.toString();
    }
}

